record_types.code:
type gsl_rng is record
   c_type : access constant gsl_rng_type;
   state  : System.Address;
end record;

type gsl_rng_type is record
   name : Interfaces.C.Strings.chars_ptr;
   max  : aliased unsigned_long;
   min  : aliased unsigned_long;
   size : aliased size_t;
   set  : access procedure
     (arg1 : System.Address;
      arg2 : unsigned_long);
   get : access function
     (arg1 : System.Address)
      return unsigned_long;
   get_double : access function
     (arg1 : System.Address)
      return double;
end record;

